from typing import Dict, Any

from typing_extensions import TypedDict, NotRequired

from geosat.cloud.metadata.private_namespace import PrivateNamespace


class Metadata(TypedDict):
    srs_wkt: NotRequired[str]
    filepath: NotRequired[str]
    # General Dict because specifying types will include laspy dependency
    las: NotRequired[Dict[str, Any]]
    geosat: NotRequired[PrivateNamespace]
